import{_ as e,o as t,c as o,ag as i}from"./chunks/framework.BYYsWsaA.js";const u=JSON.parse('{"title":"Data Validation","description":"","frontmatter":{},"headers":[],"relativePath":"sheets/data-validation.md","filePath":"sheets/data-validation.md"}'),l={name:"sheets/data-validation.md"};function r(n,a,s,d,h,c){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="data-validation" tabindex="-1">Data Validation <a class="header-anchor" href="#data-validation" aria-label="Permalink to &quot;Data Validation&quot;">​</a></h1><p>Data validation adds interactive <strong>in-cell controls</strong> — checkboxes, dropdown lists, and a date picker — and guards a range against bad input. A control is not a floating object on top of the grid; it&#39;s a special rendering of the cell&#39;s own value, so it survives sorting, filtering, and copying, and works directly in formulas.</p><h2 id="open-the-data-validation-panel" tabindex="-1">Open the Data Validation Panel <a class="header-anchor" href="#open-the-data-validation-panel" aria-label="Permalink to &quot;Open the Data Validation Panel&quot;">​</a></h2><p>Open the right-side <strong>Data validation</strong> panel in either of these ways:</p><ul><li>Click the <strong>Data validation</strong> icon in the toolbar</li><li>Right-click a cell and choose <strong>Data validation</strong></li></ul><p>On a narrow screen, the toolbar collapses its extra tools into an overflow (<strong>⋯</strong>) menu — open it and choose <strong>Data validation</strong> there.</p><h2 id="add-a-rule" tabindex="-1">Add a Rule <a class="header-anchor" href="#add-a-rule" aria-label="Permalink to &quot;Add a Rule&quot;">​</a></h2><ol><li>Click <strong>Add</strong> in the panel to create a rule</li><li>Set <strong>Apply to range</strong> — type a range like <code>B2:B100</code>, or click <strong>Use selected range</strong> to fill it from your current selection, then click <strong>Apply</strong></li><li>Pick a <strong>Criteria</strong> (see below)</li><li>Choose what happens on invalid input — <strong>Show a warning</strong> or <strong>Reject the input</strong></li></ol><p>You can add several rules per sheet; each appears as a card you can edit or delete.</p><h2 id="criteria" tabindex="-1">Criteria <a class="header-anchor" href="#criteria" aria-label="Permalink to &quot;Criteria&quot;">​</a></h2><h3 id="checkbox" tabindex="-1">Checkbox <a class="header-anchor" href="#checkbox" aria-label="Permalink to &quot;Checkbox&quot;">​</a></h3><p>Turns each cell in the range into a checkbox storing <code>TRUE</code> or <code>FALSE</code>.</p><ul><li><strong>Click</strong> the box to toggle it</li><li>Select one or more cells and press <strong>Space</strong> to toggle them together</li><li>Because the value is a real boolean, <code>=COUNTIF(B2:B100, TRUE)</code> and similar formulas work as expected</li></ul><h3 id="dropdown" tabindex="-1">Dropdown <a class="header-anchor" href="#dropdown" aria-label="Permalink to &quot;Dropdown&quot;">​</a></h3><p>Restricts the cell to a list of options you type, one per line. A dropdown arrow appears in the cell.</p><ul><li><strong>Click</strong> the arrow — or press <strong>Alt+↓</strong> — to open the option picker</li><li>Toggle <strong>Show dropdown arrow</strong> to hide the arrow while keeping the rule</li><li>Values outside the list are flagged (warning) or blocked (reject), per the rule&#39;s invalid setting</li></ul><h3 id="date" tabindex="-1">Date <a class="header-anchor" href="#date" aria-label="Permalink to &quot;Date&quot;">​</a></h3><p>Validates that the cell holds a date, with an operator:</p><table tabindex="0"><thead><tr><th>Operator</th><th>Meaning</th></tr></thead><tbody><tr><td>is a valid date</td><td>Any valid date</td></tr><tr><td>date is</td><td>Equals a specific date</td></tr><tr><td>is before / is on or before</td><td>Earlier than a date</td></tr><tr><td>is after / is on or after</td><td>Later than a date</td></tr><tr><td>is between / is not between</td><td>Within (or outside) two dates</td></tr></tbody></table><p><strong>Double-click</strong> a date-validated cell to pick a value from a calendar popover instead of typing it.</p><h3 id="number" tabindex="-1">Number <a class="header-anchor" href="#number" aria-label="Permalink to &quot;Number&quot;">​</a></h3><p>Validates numeric input with an operator:</p><ul><li>is a valid number</li><li>is equal to / is not equal to</li><li>greater than / greater than or equal to</li><li>less than / less than or equal to</li><li>between / not between</li></ul><h3 id="text" tabindex="-1">Text <a class="header-anchor" href="#text" aria-label="Permalink to &quot;Text&quot;">​</a></h3><p>Validates text input:</p><ul><li>contains / does not contain</li><li>is exactly</li><li>is valid email</li><li>is valid URL</li></ul><h2 id="handling-invalid-input" tabindex="-1">Handling Invalid Input <a class="header-anchor" href="#handling-invalid-input" aria-label="Permalink to &quot;Handling Invalid Input&quot;">​</a></h2><p>Each rule chooses how to treat a value that fails validation:</p><ul><li><strong>Show a warning</strong> — the value is accepted but the cell gets a small red marker in its corner, so you can spot it and fix it later</li><li><strong>Reject the input</strong> — the entry is refused and the cell keeps its previous value</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use <strong>warning</strong> while cleaning up existing data so nothing is lost, and switch to <strong>reject</strong> once a column should only ever hold valid values.</p></div><h2 id="remove-a-rule" tabindex="-1">Remove a Rule <a class="header-anchor" href="#remove-a-rule" aria-label="Permalink to &quot;Remove a Rule&quot;">​</a></h2><p>Open the <strong>Data validation</strong> panel and click the delete (trash) icon on the rule&#39;s card. The in-cell controls for that range are removed and the cells go back to plain values.</p>',32)])])}const g=e(l,[["render",r]]);export{u as __pageData,g as default};
